INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("boss_def_lower_limit", "バトル開始時、すべてのモンスターの物理防御力をアップさせる。この効果は物理防御力ダウンの影響を受けない。", 4100410, 10041003, "物理防御力（ダウン不可）アップ");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("boss_magic_def_lower_limit", "バトル開始時、すべてのモンスターの魔法防御力をアップさせる。この効果は魔法防御力ダウンの影響を受けない。", 4100410, 10041004, "魔法防御力（ダウン不可）アップ");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES ("boss_tp_down_cut", "バトル開始時、すべてのモンスターがＴＰダウン\n75％カット状態になる。", 4100410, 10041005, "ＴＰダウンカット");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (3, "バトル開始時、すべてのキャラのＴＰ上昇をダウンさせる。", 4100410, 10041006, "ＴＰ上昇ダウン");
INSERT INTO `v1_e13d904a1a167efd5ef59390f91feda7465b90696c995de6a1ff1af39c0a34b1` VALUES (9, "バトル開始時、すべてのキャラのＨＰ吸収をダウンさせる。", 4100410, 10041007, "ＨＰ吸収ダウン");
